args.sparql:
SELECT ?duration WHERE {
  ?game wdt:P31 wd:Q15002199;
        wdt:P172 wd:Q252558;
        wdt:P172 wd:Q252573;
        wdt:P585 ?date;
        wdt:P2145 ?duration.
  FILTER (YEAR(?date) IN (1977, 1978, 2008, 2009))
}
ORDER BY DESC(?duration)
LIMIT 1
OFFSET 2

